mapper.select:
SELECT umst.user_id , umst.user_nm , umst.use_yn , co.cd_nm AS user_co_nm FROM ad_user_mst umst ,( SELECT cd.comm_grp_cd , cd.comm_cd , cd.cd_nm FROM ad_comm_grp_cd grp, ad_comm_cd cd WHERE grp.comm_grp_cd = 'USER_CO_FG_CD' AND grp.comm_grp_cd = cd.comm_grp_cd ) co WHERE umst.user_co_fg_cd = co.comm_cd (+) AND umst.user_id not in (SELECT usr.user_id FROM ad_user_mst usr ,ad_autr_mst autr ,ad_user_autr_map amap WHERE usr.user_id = amap.user_id AND autr.autr_id = #{autrId} AND autr.autr_id = amap.autr_id AND usr.del_yn = 'N' AND usr.use_yn = 'Y') AND umst.del_yn = 'N' AND umst.use_yn = 'Y'
AND umst.user_id = #{userId}
AND UPPER(umst.user_nm) LIKE '%' || UPPER(#{userNm}) || '%'

mapper.insert:

INSERT INTO ad_autr_mst (
        autr_id
      , autr_nm
      , autr_fg_cd
      , autr_expl
      , del_yn
      , use_yn
      , stm_fir_reg_date
      , stm_fir_reg_user_id
      , stm_last_upd_date
      , stm_last_upd_user_id
    ) VALUES (
        #{autrId}
     ,  #{autrNm}
     ,  '1'
     ,  #{autrExpl}
     ,  'N'
     ,  'Y'
     ,  SYSDATE
     ,  #{regId}
     ,  SYSDATE
     ,  #{regId}
    )


INSERT INTO ad_user_autr_map(
       user_id
     , autr_id
     , stm_fir_reg_date
     , stm_fir_reg_user_id
     , stm_last_upd_date
     , stm_last_upd_user_id
) VALUES (
      #{userId}
     ,#{autrId}
     ,SYSDATE
     ,#{regId}
     ,SYSDATE
     ,#{regId}
)


INSERT INTO ad_autr_menu_map(
       autr_id
     , menu_id
     , stm_fir_reg_date
     , stm_fir_reg_user_id
     , stm_last_upd_date
     , stm_last_upd_user_id
) VALUES (
      #{autrId}
     ,#{menuId}
     ,SYSDATE
     ,#{regId}
     ,SYSDATE
     ,#{regId}
)

mapper.update:
UPDATE ad_autr_mst
SET  autr_nm = #{autrNm}
    ,autr_expl = #{autrExpl}
    ,stm_last_upd_date = SYSDATE
    ,stm_last_upd_user_id = #{regId}
WHERE AUTR_ID = #{autrId}

UPDATE ad_autr_mst
SET del_yn = 'Y'
   ,use_yn = 'N'
   ,stm_last_upd_date = SYSDATE
   ,stm_last_upd_user_id = #{regId}
WHERE AUTR_ID = #{autrId}

mapper.delete:
DELETE
FROM ad_user_autr_map
WHERE autr_id = #{autrId}
AND user_id = #{userId}
